        return "keyboard"

    def can_handle(self, intent: Intent) -> bool:
        return intent.type == IntentType.COMMAND and intent.parsed_action in (
            "volume_up",
            "volume_down",
            "mute",
            "new_tab",
            "close_tab",
            "change_tab",
            "full_screen",
            "escape",
        )

    def execute(
