def execute_by_intent(
    self,
    intent: Intent,
    context: Optional[ConversationContext] = None,
) -> SkillResult:
    # 1. Direct action routing (fastest path)
    action = getattr(intent, "parsed_action", "") or ""
    if action in self.ACTION_SKILL_MAP:
