        self._last_gesture = gesture

    # Push to sequence history (deduplicate consecutive same gesture)
    if not self._history or self._history[-1] != gesture:
        self._history.append(gesture)

    return {"state": self.state, "sequence": self.get_current_sequence()}

def transition(self, gesture: str) -> None:
    """Apply FSM transition for *gesture* from the current state."""
    key = (self.state, gesture)
    new_state = _TRANSITIONS.get(key)
    if new_state and new_state != self.state:
        self.state = new_state
        self._last_transition_time = time.monotonic()

def reset(self) -> None:
    """Reset the FSM to IDLE and clear history."""
    self.state = _S.IDLE
    self._history.clear()
    self._none_streak = 0
    self._last_gesture = "NONE"

def get_current_sequence(self) -> List[str]:
    """Return the current rolling gesture sequence as a plain list."""
    return list(self._history)

def time_in_state(self) -> float:
    """Seconds elapsed since the last state transition."""
    return time.monotonic() - self._last_transition_time

